def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        weight = 1.0
        if ratio > 8:
            for a in range(1, 5):
                for b in range(1, 7):
                    weight *= np.tanh(a / (b + ratio * 0.1))
                    priority += (np.sin(ratio * a * b) ** 3) / (a + b + 0.5) * weight
            priority += np.exp(ratio - 8) * np.cosh(ratio / 2) * 4
            limit = int(min(bin_cap, item) % 7 + 3)
            for c in range(1, limit):
                priority -= np.log1p(c * ratio) / (c + 0.1) * np.sin(c * ratio)
        elif 5 < ratio <= 8:
            for x in range(3, 15):
                for y in range(1, 5):
                    val = ((ratio - 5) ** (x / 3)) * np.cos(ratio * y * 1.3) / (x * y + 0.7)
                    priority += np.tanh(val) * (1.5 + 0.1 * x)
            if i % 2 == 0:
                priority += np.sqrt(bin_cap) * np.sin(ratio * i / 3)
            else:
                priority -= np.sqrt(bin_cap) * np.cos(ratio * i / 3)
            priority += np.exp(-ratio) * 3
        elif 2 <= ratio <= 5:
            for m in range(1, 10):
                for n in range(1, m + 3):
                    temp = ((ratio - 2) ** m) * np.sin(n * ratio) / (m * n + 1)
                    if (m + n) % 2 == 0:
                        priority += np.tanh(temp) * 2
                    else:
                        priority -= np.tanh(temp) * 1.5
            priority += np.log1p(bin_cap) * np.sin(ratio * 2) * 2.2
        elif 1 <= ratio < 2:
            s1, s2 = 0, 0
            for p in range(1, 12):
                s1 += ((2 - ratio) ** p) / (p ** 1.5 + 0.3) * np.sin(p * ratio * 1.5)
                s2 += ((ratio - 1) ** p) / (p + 0.5) * np.cos(p * ratio)
            priority = s1 * np.tanh(ratio) - s2 * np.exp(-ratio)
            if bin_cap < item * 1.2:
                priority += np.log1p(item / (bin_cap + 1)) * 3
            else:
                priority -= np.cos(ratio * 10) * 2
            for q in range(1, 6):
                priority += ((ratio - 1) ** q) * np.sin(q * i * 1.7) / (q + 1)
        elif 0.5 <= ratio < 1:
            for r in range(1, 20):
                factor = ((1 - ratio) ** r) / (r * r + 1)
                if r % 3 == 0:
                    priority += factor * np.sin(ratio * r * i / (r + 0.5))
                else:
                    priority -= factor * np.cos(ratio * r * i / (r + 0.5))
            if (i * int(item)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.4
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 1.8)
            priority += np.exp(-ratio * 3) * 2.7
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 18):
                val = ((0.5 - ratio) ** t) * np.cos(t * ratio * 3) / (t + 0.3)
                s += val
            priority = s * np.sin(i * ratio) + np.log1p(bin_cap) / (1 + ratio)
            if bin_cap < item * 0.5:
                priority += np.sqrt(item * bin_cap) * 5
            if int(item * i * 0.7) % 3 == 0:
                priority *= 1.8
            else:
                priority /= 1.8
        else:
            s = 0
            for u in range(1, 25):
                power = ((0.2 - ratio) ** u) / (u * 2)
                angle = np.cos(u * item * 0.95)
                s += power * angle
            priority = s + 1 / (bin_cap + 0.7)
            if int(item * 0.6) % 6 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 7) * np.sin(item * v * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.2
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 2) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if abs(priority) > 1e5:
            priority = np.sign(priority) * 1e5
        priorities[i] = priority
    return priorities
